class Solution {
public:
    int countLargestGroup(int n) {
        unordered_map<int, int> count;
        int maxCount = 0, result = 0;
        for (int i = 1; i <= n; ++i) {
            int sum = 0;
            for (int num = i; num > 0; num /= 10) {
                sum += num % 10;
            }
            count[sum]++;
            if (count[sum] > maxCount) {
                maxCount = count[sum];
                result = 1;
            } else if (count[sum] == maxCount) {
                result++;
            }
        }
        return result;
    }
};
